var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CN No. VCDF001D003526-63\\n<color=#ffd34c>최고 권한</color> 열람 승인 자료\\n자율기동고등첩보위성: 나이트 워치 시청각 자료","JPN":"CN No. VCDF001D003526-63\\n<color=#ffd34c>最高権限</color> 閲覧承認資料\\n自律機動高等諜報衛星: ナイトウォッチ視聴覚資料","ENG":"CN No. VCDF001D003526-63\\n<color=#ffd34c>Top Secret Clearance</color> Approved Data\\nAutonomous High-Altitude Reconnaissance Satellite: Night Watch Audio-Visual Data","TWN":"(TWN)CN No. VCDF001D003526-63\\n<color=#ffd34c>최고 권한</color> 열람 승인 자료\\n자율기동고등첩보위성: 나이트 워치 시청각 자료"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"이 사람이요?","JPN":"この人です?","ENG":"This person?","TWN":"(TWN)이 사람이요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"네. 혹시 보신 적 있습니까?","JPN":"はい。もしかして見たことがありますか?","ENG":"Yes. Have you seen him before?","TWN":"(TWN)네. 혹시 보신 적 있습니까?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"어...... 네. 제가 도와줬는데요.","JPN":"語......はい。私が手伝ったのですが。","ENG":"Uh...... Yes. I helped him.","TWN":"(TWN)어...... 네. 제가 도와줬는데요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"도와줬다고요?","JPN":"手伝ったんですって?","ENG":"You helped him?","TWN":"(TWN)도와줬다고요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"병원 문 닫고 가려는데 저 앞 벤치에 앉아 있더라고요.","JPN":"病院門閉じて行こうとするのにあの前ベンチに座っているんですよ。","ENG":"I was about to close the hospital door when he was sitting on the bench out front.","TWN":"(TWN)병원 문 닫고 가려는데 저 앞 벤치에 앉아 있더라고요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"처음엔 근처 성당에 새로 온 신부님인가 했어요.","JPN":"初めには近く聖堂に新しく来た新婦様かしました。","ENG":"At first, I thought he was a new priest at the nearby church.","TWN":"(TWN)처음엔 근처 성당에 새로 온 신부님인가 했어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그런데 가까이 가 보니까 피 냄새가 나는 거예요. 바닥에도 피가 뚝뚝 흐르는데......","JPN":"ところで近くに行ってみるから被においがすることです。床にも血がぽつりぽつりと流れるが......","ENG":"But when I got close, I smelled blood. Blood was dripping on the floor too......","TWN":"(TWN)그런데 가까이 가 보니까 피 냄새가 나는 거예요. 바닥에도 피가 뚝뚝 흐르는데......"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 치료해 줬다는 겁니까?","JPN":"それで治療してくれたというかけますか?","ENG":"So you're saying you treated him?","TWN":"(TWN)그래서 치료해 줬다는 겁니까?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"네, 동물 병원이래도 간단한 봉합 수술은 가능하니까요.","JPN":"はい、動物病院以来も簡単な縫合手術は可能であるからです。","ENG":"Yes, even though it's an animal hospital, simple sutures are possible.","TWN":"(TWN)네, 동물 병원이래도 간단한 봉합 수술은 가능하니까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"환부는 어땠습니까?","JPN":"還付はどうでしたか?","ENG":"What about the wound?","TWN":"(TWN)환부는 어땠습니까?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"어땠냐니요?","JPN":"オテッニャニヨ?","ENG":"What do you mean?","TWN":"(TWN)어땠냐니요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"자상이라거나, 화상이라거나, 환부의 상태 말입니다.","JPN":"刺傷だとか、やけどだとか、還付の状態言葉です。","ENG":"Whether it was a laceration, a burn, or the condition of the wound.","TWN":"(TWN)자상이라거나, 화상이라거나, 환부의 상태 말입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"아니, 제가 지금 알고 싶은 건 당신들이 갑자기 들이닥쳐서 막무가내로 물어보는 이유거든요.","JPN":"いや、私が今知りたいのはあなたたちが急に押し寄せてどうしようもないことで聞いてみる理由ですよ。","ENG":"No, what I want to know is why you're suddenly barging in and interrogating me like this.","TWN":"(TWN)아니, 제가 지금 알고 싶은 건 당신들이 갑자기 들이닥쳐서 막무가내로 물어보는 이유거든요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"경찰이에요? 영장은 가져왔어요?","JPN":"警察ですか?令状は持って来ましたか?","ENG":"Are you police? Do you have a warrant?","TWN":"(TWN)경찰이에요? 영장은 가져왔어요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님, 이 사람은 지금 인터폴이 적색수배령을 내린 위험 인물입니다.","JPN":"先生、この人は今インターポールが赤色数拝領を下ろした危険人物です。","ENG":"Sir, this person is a dangerous individual currently under an Interpol Red Notice.","TWN":"(TWN)선생님, 이 사람은 지금 인터폴이 적색수배령을 내린 위험 인물입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"한 시라도 빨리 찾지 않으면 무슨 일이 벌어질지 모릅니다. 저희를 도와 주십시오.","JPN":"一シラーも早く探さなければ何かが起こるかもしれないです。私どもを助けてください。","ENG":"If we don't find him as soon as possible, we don't know what will happen. Please help us.","TWN":"(TWN)한 시라도 빨리 찾지 않으면 무슨 일이 벌어질지 모릅니다. 저희를 도와 주십시오."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"적색수배령......이요? 그게 뭔데요? 위험한 거에요?","JPN":"赤色数拝領......これですか?それが何ですか?危ないんですか?","ENG":"Red Notice......? What's that? Is it dangerous?","TWN":"(TWN)적색수배령......이요? 그게 뭔데요? 위험한 거에요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"세계적으로 위험한 범죄자들만 분류하는 기준입니다.","JPN":"世界的に危ない犯罪者だけ分類する基準です。","ENG":"It's a classification used only for the world's most dangerous criminals.","TWN":"(TWN)세계적으로 위험한 범죄자들만 분류하는 기준입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그, 그래도 얘기해 봤을 때는 되게 온화한 사람이었는데요. 말투가 좀 싹퉁머리 없긴 해도요.","JPN":"彼、でも話してみた時はすごく温和な人だったのですが。口ぶりがちょっとサックトングモリないことは年も。","ENG":"B-but when I talked to him, he was a really gentle person. Though his manner of speaking was a bit blunt.","TWN":"(TWN)그, 그래도 얘기해 봤을 때는 되게 온화한 사람이었는데요. 말투가 좀 싹퉁머리 없긴 해도요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"다른 사람이랑 착각하신 거 아니에요?","JPN":"他人と勘違いしたこといやですか?","ENG":"Aren't you mistaking him for someone else?","TWN":"(TWN)다른 사람이랑 착각하신 거 아니에요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님, 이런 사람이 여러 명 돌아다닐 만큼 여기가 큰 도시였습니까?","JPN":"先生、このような人が何人か歩き回るほどここが大きい都市でありましたか?","ENG":"Sir, is this city big enough that multiple people like this would be walking around?","TWN":"(TWN)선생님, 이런 사람이 여러 명 돌아다닐 만큼 여기가 큰 도시였습니까?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"......","ENG":"......","TWN":"(TWN)......"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"성당으로 갔어요.","JPN":"聖堂に行きました。","ENG":"He went to the church.","TWN":"(TWN)성당으로 갔어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"성당이라고 하셨습니까?","JPN":"聖堂と言いましたか?","ENG":"Did you say the church?","TWN":"(TWN)성당이라고 하셨습니까?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"네. 고해성사를 해야 한다면서요.","JPN":"はい。告解聖事をしなければならないんですって。","ENG":"Yes. He said he needed to go to confession.","TWN":"(TWN)네. 고해성사를 해야 한다면서요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"출발한 지 얼마나 됐습니까?","JPN":"出発してからどのくらいでしたか?","ENG":"How long ago did he leave?","TWN":"(TWN)출발한 지 얼마나 됐습니까?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"30분...... 정도니까 별일 없으면 지금쯤 신부님과 만났을 거예요.","JPN":"30分......程度だからお変わりなければいまごろ新婦様と会ったでしょう。","ENG":"About 30 minutes...... so if nothing happened, he should have met the priest by now.","TWN":"(TWN)30분...... 정도니까 별일 없으면 지금쯤 신부님과 만났을 거예요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"다들 뭐 하고 있어! 들었으면 어서 움직이지 않고!","JPN":"みんな何している!きいたらさあ動かずに!","ENG":"What are you all doing! If you heard me, move quickly!","TWN":"(TWN)다들 뭐 하고 있어! 들었으면 어서 움직이지 않고!"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"대기 중인 인원들 전부 튀어나오라고 해! 지역 경찰에 협력 요청해서 근방 도로 모두 봉쇄시키고!","JPN":"待機中の人員全部飛び出しなさいと年!地域警察に協力要請して辺り道路皆封鎖させて!","ENG":"Tell all standby personnel to mobilize! Request cooperation from local police to block all nearby roads!","TWN":"(TWN)대기 중인 인원들 전부 튀어나오라고 해! 지역 경찰에 협력 요청해서 근방 도로 모두 봉쇄시키고!"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 잠깐만요!","JPN":"さあ、ちょっとすみません!","ENG":"W-wait a moment!","TWN":"(TWN)자, 잠깐만요!"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"나쁜 사람은 아니었어요. 정말이에요. 뭔가 오해가 있는 것 같은데.......","JPN":"悪い人ではなかったです。本当です。何か誤解があるようであるが.......","ENG":"He wasn't a bad person. Really. It seems like there's some misunderstanding.......","TWN":"(TWN)나쁜 사람은 아니었어요. 정말이에요. 뭔가 오해가 있는 것 같은데......."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님, 상대는 백 명도 넘게 살해한 테러리스트입니다. 선생님의 사적인 감정에 근거해서 취급을 바꿀 수는 없어요.","JPN":"先生、相手は百人も過ぎるように殺害したテロリストです。先生の史跡な感情に基づいて取り扱いを変えることはできないです。","ENG":"Sir, the target is a terrorist who has killed over a hundred people. We cannot change how we handle this based on your personal feelings.","TWN":"(TWN)선생님, 상대는 백 명도 넘게 살해한 테러리스트입니다. 선생님의 사적인 감정에 근거해서 취급을 바꿀 수는 없어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"협조해 주셔서 감사합니다. 이제 가시죠.","JPN":"協調してくれてありがとうございます。もう行かれます。","ENG":"Thank you for your cooperation. Let's go now.","TWN":"(TWN)협조해 주셔서 감사합니다. 이제 가시죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"네? 아니, 기다려 봐요! 뭐 하는 거에요, 지금! 그거......!","JPN":"はい?いや、待ってみます!何をするんです、今!それ......!","ENG":"Yes? No, wait! What are you doing right now! That......!","TWN":"(TWN)네? 아니, 기다려 봐요! 뭐 하는 거에요, 지금! 그거......!"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"저격수 배치 완료됐습니다.","JPN":"狙撃数配置完了しました。","ENG":"Sniper deployment complete.","TWN":"(TWN)저격수 배치 완료됐습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"좋아. 어떻게든 여기서 놈을 끝장내야 한다.","JPN":"良い。どうでもここでやつをけりをつけなければならない。","ENG":"Good. We have to finish him off here somehow.","TWN":"(TWN)좋아. 어떻게든 여기서 놈을 끝장내야 한다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"그 이교도 나부랭이가 자기 아는 걸 전부 불었다간 골치 아파져.","JPN":"その異教徒端っくれが自分分かるのを全部吹いたら頭痛くなる。","ENG":"If that heretic spills everything he knows, it'll be a headache.","TWN":"(TWN)그 이교도 나부랭이가 자기 아는 걸 전부 불었다간 골치 아파져."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"이번에 놓치면 끝이다. 우리 목이 달려 있다는 걸 명심하도록.","JPN":"今回逃せば終りである。私たちの首が走っているというのを肝に銘ずるように。","ENG":"If we miss him this time, it's over. Remember that our necks are on the line.","TWN":"(TWN)이번에 놓치면 끝이다. 우리 목이 달려 있다는 걸 명심하도록."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"작전 개시. 위대한 예지께서 굽어살피고 계신다.","JPN":"作戦開始。偉大な予知が照覧していらっしゃる。","ENG":"Operation commence. The Great Oracle is watching over us.","TWN":"(TWN)작전 개시. 위대한 예지께서 굽어살피고 계신다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};